"use client";

import { useState } from "react";
import dynamic from "next/dynamic";
import { useDesignStore } from "@/stores/useDesignStore";
import { EditorToolbar } from "./EditorToolbar";
import { BeadCatalogPanel } from "./BeadCatalogPanel";

// Dynamically import Scene to avoid SSR issues with Three.js / WebGL
const Scene = dynamic(() => import("@/components/scene/Scene"), {
  ssr: false,
});

/**
 * Main editor layout: full-viewport 3D canvas with bottom toolbar and
 * slide-up catalog bottom sheet.
 *
 * EditorCanvas is the Zustand subscriber that bridges store ↔ scene.
 * The Scene component stays "dumb" — it receives beads as a prop.
 */
export default function EditorCanvas() {
  const [catalogOpen, setCatalogOpen] = useState(false);

  // Subscribe to design store
  const beads = useDesignStore((s) => s.beads);
  const selectedBeadId = useDesignStore((s) => s.selectedBeadId);

  return (
    <div className="relative w-screen h-screen flex flex-col overflow-hidden">
      {/* ── 3D Canvas Area ────────────────────────────────────────── */}
      {/* touch-action: none on canvas-container prevents browser
          scroll/zoom gestures on touch devices */}
      <div className="canvas-container flex-1 w-full relative">
        <Scene beads={beads} selectedBeadId={selectedBeadId} />
      </div>

      {/* ── Catalog Bottom Sheet ─────────────────────────────────── */}
      <BeadCatalogPanel
        isOpen={catalogOpen}
        onClose={() => setCatalogOpen(false)}
      />

      {/* ── Bottom Toolbar ───────────────────────────────────────── */}
      <EditorToolbar
        catalogOpen={catalogOpen}
        onToggleCatalog={() => setCatalogOpen((prev) => !prev)}
      />
    </div>
  );
}

import LZString from "lz-string";
import type { BeadState, SerializableDesign } from "@/types/bead";

/**
 * Encode an array of BeadState objects into a URL-safe design code.
 *
 * Pipeline: filter beads with catalogBeadId → JSON.stringify → LZ-String compress → base64url.
 * Only beads that have a `catalogBeadId` are included; others are silently skipped.
 */
export function encodeDesign(beads: BeadState[]): string {
  const catalogIds = beads
    .filter((b) => b.catalogBeadId)
    .map((b) => b.catalogBeadId as string);

  const design: SerializableDesign = {
    v: 1,
    p: "pacifier-holder",
    b: catalogIds,
  };

  return LZString.compressToEncodedURIComponent(JSON.stringify(design));
}

/**
 * Decode a URL-safe design code back into a SerializableDesign.
 *
 * Applies `decodeURIComponent` first because lz-string output may contain
 * `+` which browsers encode as `%2B` in URL path segments, and Next.js
 * does not decode `%2B` back to `+` in dynamic route params.
 *
 * Returns `null` for any invalid input: malformed base64url, invalid JSON,
 * missing required fields, or unsupported version.
 */
export function decodeDesign(code: string): SerializableDesign | null {
  if (!code || typeof code !== "string") return null;

  try {
    // Normalize URL-encoded characters (e.g. %2B → +) that may appear
    // when design codes are embedded in URL path segments.
    const normalized = decodeURIComponent(code);

    const json = LZString.decompressFromEncodedURIComponent(normalized);
    if (!json) return null;

    const parsed: unknown = JSON.parse(json);

    const obj = parsed as Record<string, unknown>;
    if (obj.v !== 1 || typeof obj.p !== "string" || !Array.isArray(obj.b)) {
      return null;
    }
    if (!(obj.b as unknown[]).every((id) => typeof id === "string")) {
      return null;
    }

    return parsed as SerializableDesign;
  } catch {
    return null;
  }
}

import { create } from "zustand";
import type { BeadState } from "@/types/bead";
import { CATALOG_BEADS, getCatalogBead } from "@/data/catalogBeads";
import { catalogBeadToBeadState } from "@/lib/catalogUtils";

// ── Default chain ────────────────────────────────────────────────────────────
// Same 7 default beads as useBeadChain's DEFAULT_BEADS.

const DEFAULT_BEADS: BeadState[] = [
  { id: "bead-1", type: "wood", radius: 0.2, color: "#D4A574" },
  { id: "bead-2", type: "silicone", radius: 0.18, color: "#FF6B9D" },
  { id: "bead-3", type: "wood", radius: 0.22, color: "#C4956A" },
  { id: "bead-4", type: "plastic", radius: 0.19, color: "#6EC1E4" },
  { id: "bead-5", type: "wood", radius: 0.21, color: "#B8860B" },
  { id: "bead-6", type: "silicone", radius: 0.17, color: "#E8A0BF" },
  { id: "bead-7", type: "wood", radius: 0.2, color: "#DEB887" },
];

const MAX_CHAIN_LENGTH = 40;

// ── Store interface ──────────────────────────────────────────────────────────

export interface DesignState {
  beads: BeadState[];
  selectedBeadId: string | null;
  productType: "pacifier-holder";

  addBead: (catalogBeadId: string) => void;
  removeBead: (id: string) => void;
  removeSelected: () => void;
  selectBead: (id: string | null) => void;
  resetDesign: () => void;
  loadFromCatalogIds: (ids: string[]) => void;
  clearDesign: () => void;
}

// ── Store ────────────────────────────────────────────────────────────────────

export const useDesignStore = create<DesignState>((set, get) => ({
  beads: DEFAULT_BEADS,
  selectedBeadId: null,
  productType: "pacifier-holder",

  addBead: (catalogBeadId: string) => {
    if (get().beads.length >= MAX_CHAIN_LENGTH) return;

    const catalogBead = CATALOG_BEADS.find((b) => b.id === catalogBeadId);
    if (!catalogBead) return;

    const beadState = catalogBeadToBeadState(catalogBead);
    set((state) => ({ beads: [...state.beads, beadState] }));
  },

  removeBead: (id: string) => {
    set((state) => {
      const removed = state.beads.find((b) => b.id === id);
      return {
        beads: state.beads.filter((b) => b.id !== id),
        selectedBeadId: removed?.id === state.selectedBeadId ? null : state.selectedBeadId,
      };
    });
  },

  removeSelected: () => {
    const { selectedBeadId } = get();
    if (!selectedBeadId) return;

    set((state) => ({
      beads: state.beads.filter((b) => b.id !== selectedBeadId),
      selectedBeadId: null,
    }));
  },

  selectBead: (id: string | null) => {
    set({ selectedBeadId: id });
  },

  resetDesign: () => {
    set({ beads: DEFAULT_BEADS, selectedBeadId: null });
  },

  loadFromCatalogIds: (ids: string[]) => {
    const beads: BeadState[] = [];
    for (const id of ids) {
      const catalogBead = getCatalogBead(id);
      if (catalogBead) {
        beads.push(catalogBeadToBeadState(catalogBead));
      }
    }
    set({ beads, selectedBeadId: null });
  },

  clearDesign: () => {
    set({ beads: [], selectedBeadId: null });
  },
}));

"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { decodeDesign } from "@/lib/serialization";
import { useDesignStore } from "@/stores/useDesignStore";
import EditorCanvas from "./EditorCanvas";

interface DesignLoaderProps {
  code: string;
}

/**
 * Client boundary for the /design/[code] share page.
 *
 * Decodes a URL-safe design code on mount, loads beads into the store,
 * then renders the EditorCanvas. Shows a spinner while decoding and an
 * error state with a link home if the code is invalid.
 */
export default function DesignLoader({ code }: DesignLoaderProps) {
  const [status, setStatus] = useState<"loading" | "loaded" | "error">(
    "loading"
  );

  useEffect(() => {
    const design = decodeDesign(code);
    if (design) {
      useDesignStore.getState().loadFromCatalogIds(design.b);
      setStatus("loaded");
    } else {
      setStatus("error");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [code]);

  if (status === "loading") {
    return (
      <div className="flex items-center justify-center w-screen h-screen bg-gray-50">
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 border-2 border-gray-300 border-t-gray-600 rounded-full animate-spin" />
          <p className="text-sm text-gray-400 select-none">
            Загрузка дизайна…
          </p>
        </div>
      </div>
    );
  }

  if (status === "error") {
    return (
      <div className="flex items-center justify-center w-screen h-screen bg-gray-50">
        <div className="flex flex-col items-center gap-4 text-center px-6">
          <div className="w-14 h-14 rounded-full bg-rose-50 flex items-center justify-center">
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="24"
              height="24"
              viewBox="0 0 24 24"
              fill="none"
              stroke="#e11d48"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <circle cx="12" cy="12" r="10" />
              <line x1="15" y1="9" x2="9" y2="15" />
              <line x1="9" y1="9" x2="15" y2="15" />
            </svg>
          </div>
          <p className="text-lg font-medium text-gray-700">
            Неверная ссылка
          </p>
          <p className="text-sm text-gray-400 max-w-xs">
            Этот дизайн не найдён или ссылка повреждена.
          </p>
          <Link
            href="/"
            className="inline-flex items-center gap-1.5 px-4 py-2 text-sm font-medium rounded-xl bg-blue-50 text-blue-700 hover:bg-blue-100 transition-colors"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="14"
              height="14"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M19 12H5" />
              <path d="M12 19l-7-7 7-7" />
            </svg>
            Вернуться на главную
          </Link>
        </div>
      </div>
    );
  }

  return <EditorCanvas />;
}

import DesignLoader from "@/components/editor/DesignLoader";

/**
 * Server Component for the /design/[code] share route.
 *
 * Extracts the URL parameter and delegates to the DesignLoader client
 * boundary, which handles decoding, store loading, and error states.
 *
 * Next.js 16: params is a Promise that must be awaited.
 */
export default async function DesignSharePage({
  params,
}: {
  params: Promise<{ code: string }>;
}) {
  const { code } = await params;
  return <DesignLoader code={code} />;
}

"use client";

import { useEffect } from "react";
import { useDesignStore } from "@/stores/useDesignStore";
import EditorCanvas from "@/components/editor/EditorCanvas";

/**
 * Blank editor page for "Начать с нуля" (start from scratch).
 *
 * Clears the store on mount to ensure no leftover beads from a previous
 * session leak through, then renders the EditorCanvas.
 */
export default function EditorPage() {
  useEffect(() => {
    useDesignStore.getState().clearDesign();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return <EditorCanvas />;
}

